/*==============================================================*/
/* Table: CDTLOC                                                */
/*==============================================================*/
CREATE TABLE CDTLOC
(
    ID_CDTLOC_CODE       INT NOT NULL AUTO_INCREMENT,
    CDTLOC_LOCATION      VARCHAR(16) NOT NULL,
    CDTLOC_DESCRIPTION   VARCHAR(64) NOT NULL,
    CDTLOC_VALID_FROM    TIMESTAMP,
    CDTLOC_VALID_TO      TIMESTAMP NULL,
    CDTLOC_CREATED_BY    VARCHAR(16),
    CDTLOC_UPDATED_BY    VARCHAR(16),
    CDTLOC_CREATED_AT    TIMESTAMP,
    CDTLOC_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CDTLOC_CODE)
);

ALTER TABLE CDTLOC COMMENT 'UBICACION';

/*==============================================================*/
/* Table: CDTDOC                                                */
/*==============================================================*/
CREATE TABLE CDTDOC
(
    ID_CDTDOC_CODE       INT NOT NULL AUTO_INCREMENT,
    CDTDOC_NAME          VARCHAR(16) NOT NULL,
    CDTDOC_DESCRIPTION   VARCHAR(128),
    CDTDOC_VALID_FROM    TIMESTAMP,
    CDTDOC_VALID_TO      TIMESTAMP NULL,
    CDTDOC_CREATED_BY    VARCHAR(16),
    CDTDOC_UPDATED_BY    VARCHAR(16),
    CDTDOC_CREATED_AT    TIMESTAMP,
    CDTDOC_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CDTDOC_CODE)
);

ALTER TABLE CDTDOC COMMENT 'TIPO DOCUMENTO';

/*==============================================================*/
/* Table: CDTOPT                                                */
/*==============================================================*/
CREATE TABLE CDTOPT
(
    ID_CDTOPT_CODE       INT NOT NULL AUTO_INCREMENT,
    XID_CDTDOC_CODE      INT,
    CDTOPT_NAME          VARCHAR(64) NOT NULL,
    CDTOPT_DESCRIPTION   VARCHAR(128),
    CDTOPT_VALID_FROM    TIMESTAMP,
    CDTOPT_VALID_TO      TIMESTAMP NULL,
    CDTOPT_CREATED_BY    VARCHAR(16),
    CDTOPT_UPDATED_BY    VARCHAR(16),
    CDTOPT_CREATED_AT    TIMESTAMP,
    CDTOPT_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CDTOPT_CODE)
);

ALTER TABLE CDTDOC COMMENT 'OPCIONES DOCUMENTO';

/*==============================================================*/
/* Table: CDTCELL                                               */
/*==============================================================*/
CREATE TABLE CDTCELL
(
    ID_CDTCELL_CODE      INT NOT NULL AUTO_INCREMENT,
    XID_CDTCAT_ID        INT,
    XID_CDTLOC_CODE      INT,
    XID_CDTDOC_CODE      INT,
    CDTCELL_NUM_DOC      VARCHAR(16) NOT NULL,
    CDTCELL_LOTE         VARCHAR(16) NOT NULL,
    CDTCELL_AMOUNT       INT,
    CDTCELL_BALANCE      INT,
    CDTCELL_COAT         INT,
    CDTCELL_PALLETS      INT,
    CDTCELL_WEIGHT       INT,
    CDTCELL_DATE         TIMESTAMP NOT NULL,
    CDTCELL_OBSERVATION  VARCHAR(128),
    CDTCELL_VALID_FROM   TIMESTAMP,
    CDTCELL_VALID_TO     TIMESTAMP NULL,
    CDTCELL_CREATED_BY   VARCHAR(16),
    CDTCELL_UPDATED_BY   VARCHAR(16),
    CDTCELL_CREATED_AT   TIMESTAMP,
    CDTCELL_UPDATED_AT   TIMESTAMP,
    PRIMARY KEY (ID_CDTCELL_CODE)
);

ALTER TABLE CDTCELL COMMENT 'BODEGA';

ALTER TABLE CDTCELL ADD CONSTRAINT XID_CDTCELL_CODE_XID_CDTCAT_CODE FOREIGN KEY (XID_CDTCAT_ID)
    REFERENCES CDTCAT (ID_CDTCAT_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CDTCELL ADD CONSTRAINT XID_CDTCELL_CODE_XID_CDTLOC_CODE FOREIGN KEY (XID_CDTLOC_CODE)
    REFERENCES CDTLOC (ID_CDTLOC_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CDTCELL ADD CONSTRAINT XID_CDTCELL_CODE_XID_CDTDOC_CODE FOREIGN KEY (XID_CDTDOC_CODE)
    REFERENCES CDTDOC (ID_CDTDOC_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CDTOPT ADD CONSTRAINT XID_CDTOPT_CODE_XID_CDTDOC_CODE FOREIGN KEY (XID_CDTDOC_CODE)
    REFERENCES CDTDOC (ID_CDTDOC_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;







